import theme from "../utils/theme"
export default class Carousel extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    shadowRoot.innerHTML = `
      <style>
        :host {
          font-family: var(--font-family);
          font-size: 18px;
          display: inline-block;
        } 
        [role="tablist"] {
          display: flex;
          flex-direction: row;
          align-items: center;
          justify-content: center;
          margin-top: 10px;
          gap: 10px;
        }
        [role="tab"] {
          border: none;
          height: 6px;
          width: 40px;
          border-radius: 10px;
          cursor: pointer;
          background: var(--background-secondary);
        }
        button[aria-selected="true"] {
          background-color: var(--text-primary);
        }
      </style>
      <section id="carousel" aria-roledescription="carousel" aria-label="highlighted shows">
        <div class="carousel-inner">
          <div id="carousel-items" class="carousel-items playing" aria-live="off">
            <slot></slot>
          </div>
          <div class="controls">
            <div class="tab-wrapper">
              <div id="tablist" role="tablist" aria-label="slides">
              </div>
            </div>
          </div>
        </div>
      </section>    
    `
  }

  getTabButton = ({id, idx}) => {
    return `
      <button 
        id="carousel-tab-${idx + 1}" 
        type="button" 
        role="tab" 
        aria-selected=${idx === 0 ? "true" : "false"}
        aria-label="slide ${idx + 1}"
      >
      </button> 
    `
  }

  renderTabButton = e => {
    const nodes = Array.from(this.querySelectorAll("huanlin-carousel-item"))
    const tablist = this.shadowRoot.querySelector("#tablist")
    let innerHTML = ""
    nodes.forEach((n, idx) => {
      const id = n.getAttribute("id")
      innerHTML += this.getTabButton({id, idx})
    })
    tablist.innerHTML = innerHTML
  }

  handleSlotChange = () => {
    const slot = this.shadowRoot.querySelector("slot");
    slot.addEventListener("slotchange", this.renderTabButton)
  }

  handleTablistClick = e => {
    if (e.target.getAttribute("role") !== "tab") return
    const buttonList  = Array.from(e.currentTarget.querySelectorAll("[role='tab']"))
    const itemList  = Array.from(this.querySelectorAll("huanlin-carousel-item"))
    buttonList.forEach((btn, i) => {
      if (btn === e.target) {
        btn.setAttribute("aria-selected", "true")
        itemList[i].setAttribute("active", "")
      } else {
        btn.setAttribute("aria-selected", "false")
        itemList[i].removeAttribute("active")
      }
    })
  }

  setFirstItemActive = () => {
    const item  = this.querySelector("huanlin-carousel-item")
    item && item.setAttribute("active", "")
  }

  handleTablistKeyboard = e => {
    const tabList = Array.from(e.currentTarget.querySelectorAll("[role='tab']"))
    const itemList  = Array.from(this.querySelectorAll("huanlin-carousel-item"))
    let idx = tabList.indexOf(e.target)
    if (e.key === "ArrowLeft") {
      idx -= 1 
    } else if (e.key === "ArrowRight") {
      idx += 1 
    }
    if (idx < 0 || idx >= tabList.length) return
    tabList.forEach((tab, i) => {
      if (i === idx) {
        tab.setAttribute("aria-selected", "true")
        tab.setAttribute("tabindex", "0")
        tab.focus()
        itemList[i].setAttribute("active", "")
      } else {
        tab.setAttribute("aria-selected", "false")
        tab.removeAttribute("tabindex", "-1")
        itemList[i].removeAttribute("active")
      }
    })
  }


  connectedCallback() {
    this.classList.add("hydrated")
    this.render()
    this.handleSlotChange()
    this.renderTabButton()
    this.setFirstItemActive()
    this.shadowRoot.querySelector("#tablist").addEventListener("click", this.handleTablistClick)
    this.shadowRoot.querySelector("[role='tablist']").addEventListener("keydown", this.handleTablistKeyboard)
  }
  disconnectedCallback() {
    this.shadowRoot.querySelector("#tablist").removeEventListener("click", this.handleTablistClick)
    this.shadowRoot.querySelector("[role='tablist']").removeEventListener("keydown", this.handleTablistKeyboard)
    const slot = this.shadowRoot.querySelector("slot");
    slot.removeEventListener("slotchange", this.renderTabButton)
  }

  render = () => {
  }
}
